final:
module top_module(
    input [7:0] ERR_A,
    input [7:0] B,
    input [2:0] op,
    output reg [7:0] C
);always @(*) begin
    case (op)
        3'b000: C = ERR_A + B;
        3'b001: C = ERR_A - B;
        3'b010: C = ERR_A * B;
        3'b011: if (B == 8'b0) C = 8'b11111111; else C = ERR_A / B;
        default: C = 8'b00000000;
    endcase
end

endmodule
